#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX 1000000
int chefonacci[MAX];
int dp[MAX][11];
int main() {
    int Q;
    scanf("%d", &Q);
    while (Q--) {
        int X, K;
        scanf("%d %d", &X, &K);
        chefonacci[0] = 1;
        chefonacci[1] = 2;
        for (int i = 2; i < MAX; i++) {
            chefonacci[i] = (chefonacci[i-1] + chefonacci[i-2]) % MOD;
        }
        for (int i = 0; i < MAX; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i < MAX; i++) {
            for (int j = 1; j <= K; j++) {
                for (int k = 0; k < i; k++) {
                    if (chefonacci[k] <= i) {
                        dp[i][j] = (dp[i][j] + dp[i-chefonacci[k]][j-1]) % MOD;
                    }
                }
            }
        }
        printf("%d\n", dp[X][K]);
    }
    return 0;
}

