const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
const MAX = 1000000;
const chefonacci = new Array(MAX).fill(0);
const dp = new Array(MAX).fill(0).map(() => new Array(11).fill(0));
function nextLine() {
    return input[idx++];
}
function nextInt() {
    return parseInt(nextLine());
}
function nextInts() {
    return nextLine().split(' ').map(Number);
}
const Q = nextInt();
for (let i = 0; i < Q; i++) {
    const [X, K] = nextInts();
    chefonacci[0] = 1;
    chefonacci[1] = 2;
    for (let j = 2; j < MAX; j++) {
        chefonacci[j] = (chefonacci[j-1] + chefonacci[j-2]) % MOD;
    }
    for (let j = 0; j < MAX; j++) {
        for (let k = 0; k <= K; k++) {
            dp[j][k] = 0;
        }
    }
    dp[0][0] = 1;
    for (let j = 1; j < MAX; j++) {
        for (let k = 1; k <= K; k++) {
            for (let l = 0; l < j; l++) {
                if (chefonacci[l] <= j) {
                    dp[j][k] = (dp[j][k] + dp[j-chefonacci[l]][k-1]) % MOD;
                }
            }
        }
    }
    console.log(dp[X][K]);
}

